  ('heelevel3-d592fc58-moex-00120', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '在計算本國之國民所得時，有關本國人王先生在美國出差之工作所得，下列敘述何者正確？', '["不應列入GNP計算", "應列入為淨國民收入（NetNationalIncome）項目內", "應該列入GDP", "應該同時列入本國之GDP與GNP"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00121', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '提款機的普及讓貨幣的流通速度加快。在古典二分（classicaldichotomy）的前提之下，下列何者 為最有可能發生的結果？', '["所得提高", "所得降低", "實質貨幣數量提高", "實質貨幣數量降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00122', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '若世界各國生產函數為Y=AKαL1-α，α (0,1)，其中Y為產出，A為技術水準，L為勞動，K為資本。據 此生產函數，關於新古典成長模型之收斂假說，下列敘述何者正確？', '["無論技術如何進步，絕對收斂假說∈及相對收斂假說於此均不成立", "技術進步會導致各國經濟成長率高於技術進步率，則相對收斂假說不成立，但絕對收斂假說會 成立", "技術進步下，各國經濟成長率會等於技術進步率，則絕對收斂假說不成立，但相對收斂假說會 成立", "無論經濟成長率與技術進步率關係為何，絕對收斂假說及相對收斂假說均成立 32460、32760"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00123', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '當皮古效果（Pigoueffect）存在時，下列敘述何者正確？', '["總合供給線呈正斜率", "總合供給線呈垂直線", "總合需求線呈負斜率", "總合需求線呈水平線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00124', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '當經濟體系落入流動性陷阱時，下列三項敘述，正確的有幾項？①財政政策沒有排擠效果  ②貨', '["傳統貨幣政策最有效", "0項", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00125', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '有關新興凱因斯學派模型（NewKeynesianModel）的敘述，下列何者正確？', '["新興凱因斯學派模型認為，並非所有的工資及物價調整都是在同一時間進行，以致於工資與物 價錯開調整現象將使整體物價水準在面臨需求變動之時，呈現緩慢調整現象", "在勞動契約架構下，長期總合供給曲線是正斜率，從而貨幣在短期並非中立性（non-neutrality）", "在物價黏滯（stickiness）下，當民眾能理性預期，清楚知道貨幣政策未來如何走向時，貨幣政 策短期仍然無法影響實質產出", "獨占性競爭與物價黏滯二者同為實質景氣循環模型（RealBusinessCycleModel）與新興凱因斯 學派模型中的重要特性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00126', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-112-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'single_choice', '短期總合供給曲線和總合需求曲線交點下的產出水準：', '["永遠小於充分就業的產出", "永遠大於充分就業的產出", "永遠等於充分就業的產出", "有可能大於、等於或小於充分就業的產出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:53+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "333", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL)
